#include <WiFi.h>
#include <Firebase_ESP_Client.h>
#include "addons/TokenHelper.h"

// Wi-Fi Configuration
#define WIFI_SSID "Your_WiFi_Name"
#define WIFI_PASSWORD "Your_WiFi_Password"

// Firebase Configuration
#define API_KEY "Your_Firebase_API_Key"
#define DATABASE_URL "https://your-database-url.firebaseio.com/"

FirebaseData fbdo;
FirebaseAuth auth;
FirebaseConfig config;

void setup() {
  Serial.begin(115200);
  WiFi.begin(WIFI_SSID, WIFI_PASSWORD);
  Serial.print("Connecting to Wi-Fi");
  while (WiFi.status() != WL_CONNECTED) {
    Serial.print(".");
    delay(300);
  }
  Serial.println();
  Serial.print("Connected to Wi-Fi, IP: ");
  Serial.println(WiFi.localIP());

  config.api_key = API_KEY;
  config.database_url = DATABASE_URL;

  Firebase.begin(&config, &auth);
  Firebase.reconnectWiFi(true);
}

To set up Firebase Realtime Database:
1. Go to Firebase Console, create a new project named 'AquaFlowproj'.
2. Disable Google Analytics and create the project.
3. In Build → Realtime Database, create a new database in Test Mode and choose your region.
4. At the root, add the nodes: `/data`, `/pump`, `/flow1`, `/flow2`.
5. Set database rules to allow read and write access:

{
  "rules": {
    ".read": true,
    ".write": true,
    "data": {
      ".read": true,
      ".write": true
    },
    "pump": {
      ".read": true,
      ".write": true
    },
    "flow1": {
      ".read": true,
      ".write": true
    },
    "flow2": {
      ".read": true,
      ".write": true
    }
  }
}

6. Enable Email/Password authentication and create a user account for the web dashboard.
